494	class _FlipCountdown extends StatefulWidget {
495	  final DateTime expiresAt;
496	  const _FlipCountdown({required this.expiresAt});
497	
498	  @override
499	  State<_FlipCountdown> createState() => _FlipCountdownState();
500	}
501	
502	class _FlipCountdownState extends State<_FlipCountdown> {
503	  late Timer _timer;
504	  Duration _remaining = Duration.zero;
505	
506	  @override
507	  void initState() {
508	    super.initState();
509	    _update();
510	    _timer = Timer.periodic(const Duration(seconds: 1), (_) => _update());
511	  }
512	
513	  void _update() {
514	    final r = widget.expiresAt.difference(DateTime.now());
515	    setState(() => _remaining = r.isNegative ? Duration.zero : r);
516	  }
517	
518	  @override
519	  void dispose() {
520	    _timer.cancel();
521	    super.dispose();
522	  }
523	
524	  @override
525	  Widget build(BuildContext context) {
526	    final h = _remaining.inHours.toString().padLeft(2, '0');
527	    final m = (_remaining.inMinutes % 60).toString().padLeft(2, '0');
528	    final s = (_remaining.inSeconds % 60).toString().padLeft(2, '0');
529	    return Row(
530	      mainAxisAlignment: MainAxisAlignment.center,
531	      children: [
532	        _seg(h, 'h'),
533	        _sep(),
534	        _seg(m, 'm'),
535	        _sep(),
536	        _seg(s, 's'),
537	      ],
538	    );
539	  }
540	
541	  Widget _seg(String val, String prefix) => Row(
542	        mainAxisSize: MainAxisSize.min,
543	        children: [
544	          for (int i = 0; i < val.length; i++) _digit(val[i], '$prefix$i'),
545	        ],
546	      );
547	
548	  Widget _digit(String d, String keyPrefix) => AnimatedSwitcher(
549	        duration: const Duration(milliseconds: 220),
550	        transitionBuilder: (child, anim) => ScaleTransition(
551	          scale: anim,
552	          child: FadeTransition(opacity: anim, child: child),
553	        ),
554	        child: Container(
555	          key: ValueKey('$keyPrefix:$d'),
556	          width: 30,
557	          height: 44,
558	          margin: const EdgeInsets.symmetric(horizontal: 1.5),
559	          decoration: BoxDecoration(
560	            color: const Color(0xFF2A1F00),
561	            borderRadius: BorderRadius.circular(5),
562	            border: Border.all(
563	                color: const Color(0xFFFFC107).withOpacity(0.35), width: 1),
564	          ),
565	          alignment: Alignment.center,
566	          child: Text(
567	            d,
568	            style: const TextStyle(
569	              color: Color(0xFFFFC107),
570	              fontSize: 24,
571	              fontWeight: FontWeight.bold,
572	            ),
573	          ),
574	        ),
575	      );
576	
577	  Widget _sep() => const Padding(
578	        padding: EdgeInsets.only(left: 3, right: 3, bottom: 4),
579	        child: Text(
580	          ':',
581	          style: TextStyle(
582	              color: Color(0xFFFFC107),
583	              fontSize: 28,
584	              fontWeight: FontWeight.bold),
585	        ),
586	      );
587	}
