import 'dart:async';
import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:shared_preferences/shared_preferences.dart';
import 'profile_screen.dart';

class WhoILikeScreen extends StatefulWidget {
  final Function(int) onSwitchTab;

  const WhoILikeScreen({super.key, required this.onSwitchTab});

  @override
  State<WhoILikeScreen> createState() => _WhoILikeScreenState();
}

class _DailyLockInfo {
  final int id;
  final String status;
  final DateTime expiresAt;
  final int lockedUserId;
  final String lockedUsername;

  _DailyLockInfo({
    required this.id,
    required this.status,
    required this.expiresAt,
    required this.lockedUserId,
    required this.lockedUsername,
  });

  factory _DailyLockInfo.fromJson(Map<String, dynamic> json) {
    final lockedUser = (json['locked_user'] as Map<String, dynamic>?) ??
        (json['liked_user'] as Map<String, dynamic>?) ??
        {};
    return _DailyLockInfo(
      id: json['id'] as int,
      status: json['status'] as String? ?? 'pending',
      expiresAt: DateTime.parse(json['expires_at'] as String),
      lockedUserId:
          (lockedUser['id'] as int?) ?? (json['liked_id'] as int?) ?? 0,
      lockedUsername: (lockedUser['username'] as String?) ?? '',
    );
  }
}

class _WhoILikeScreenState extends State<WhoILikeScreen> {
  static const _bg = Color(0xFF0E0E0E);
  static const _baseUrl = 'http://10.0.2.2:8000';

  bool _isLoading = true;
  String? _error;
  List<Map<String, dynamic>> _likes = [];
  _DailyLockInfo? _activeLock;

  // Unique colour per rank — cycles after 12
  static const _rankColors = [
    Color(0xFFFFC107), //  1 - amber
    Color(0xFFFF5722), //  2 - deep orange
    Color(0xFFE91E8C), //  3 - pink
    Color(0xFF00BCD4), //  4 - cyan
    Color(0xFF8BC34A), //  5 - light green
    Color(0xFF9C27B0), //  6 - purple
    Color(0xFF03A9F4), //  7 - light blue
    Color(0xFFFF9800), //  8 - orange
    Color(0xFF4CAF50), //  9 - green
    Color(0xFFF44336), // 10 - red
    Color(0xFF00E5FF), // 11 - cyan accent
    Color(0xFFCDDC39), // 12 - lime
  ];

  Color _rankColor(int rank) {
    return _rankColors[(rank - 1) % _rankColors.length];
  }

  @override
  void initState() {
    super.initState();
    _loadLikes();
  }

  Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  Future<void> _loadLikes() async {
    setState(() {
      _isLoading = true;
      _error = null;
    });
    try {
      final token = await _getToken();
      final headers = {'Authorization': 'Bearer $token'};

      final results = await Future.wait([
        http.get(Uri.parse('$_baseUrl/api/who_i_like'), headers: headers),
        http.get(Uri.parse('$_baseUrl/api/daily-lock'), headers: headers),
      ]);

      final likesRes = results[0];
      final lockRes = results[1];

      _DailyLockInfo? lock;
      if (lockRes.statusCode == 200) {
        try {
          final lockData = jsonDecode(lockRes.body) as Map<String, dynamic>;
          final asLiker = lockData['as_liker'] as Map<String, dynamic>?;
          if (asLiker != null && asLiker['status'] == 'pending') {
            lock = _DailyLockInfo.fromJson(asLiker);
          }
        } catch (_) {}
      }

      if (likesRes.statusCode == 200) {
        final data = jsonDecode(likesRes.body) as Map<String, dynamic>;
        setState(() {
          _likes =
              (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
          _activeLock = lock;
          _isLoading = false;
        });
      } else {
        setState(() {
          _error = 'Failed (${likesRes.statusCode})';
          _isLoading = false;
        });
      }
    } catch (e) {
      setState(() {
        _error = 'Error: $e';
        _isLoading = false;
      });
    }
  }

  Future<void> _pushRerank() async {
    try {
      final token = await _getToken();
      final rankings = _likes.asMap().entries.map((e) {
        return {'username': e.value['username'], 'rank': e.key + 1};
      }).toList();
      await http.put(
