        padding: const EdgeInsets.only(top: 8, bottom: 80),
        itemCount: _likes.length,
        onReorder: (oldIndex, newIndex) {
          setState(() {
            if (newIndex > oldIndex) newIndex--;
            final item = _likes.removeAt(oldIndex);
            _likes.insert(newIndex, item);
          });
          _pushRerank();
        },
        itemBuilder: (context, index) {
          final user = _likes[index];
          final rank = index + 1;
          final int userId = user['id'] as int? ?? 0;
          final String username = user['username'] as String? ?? '';
          final int? age = user['age'] as int?;
          final String? sex = user['sex'] as String?;
          final String photoUrl = '$_baseUrl/api/users/$userId/photo';
          final bool isLocked = rank == 1 && _activeLock != null;

          return _WhoILikeTile(
            key: ValueKey(userId),
