// ── Flip countdown ────────────────────────────────────────────────────────────

class _FlipCountdown extends StatefulWidget {
  final DateTime expiresAt;
  const _FlipCountdown({required this.expiresAt});

  @override
  State<_FlipCountdown> createState() => _FlipCountdownState();
}

class _FlipCountdownState extends State<_FlipCountdown> {
  late Timer _timer;
  Duration _remaining = Duration.zero;

  @override
  void initState() {
    super.initState();
    _update();
    _timer = Timer.periodic(const Duration(seconds: 1), (_) => _update());
  }

  void _update() {
    final r = widget.expiresAt.difference(DateTime.now());
    setState(() => _remaining = r.isNegative ? Duration.zero : r);
  }

  @override
  void dispose() {
    _timer.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final h = _remaining.inHours.toString().padLeft(2, '0');
    final m = (_remaining.inMinutes % 60).toString().padLeft(2, '0');
    final s = (_remaining.inSeconds % 60).toString().padLeft(2, '0');
    return Row(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        _seg(h, 'h'),
        _sep(),
        _seg(m, 'm'),
        _sep(),
        _seg(s, 's'),
      ],
    );
  }

  Widget _seg(String val, String prefix) => Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          for (int i = 0; i < val.length; i++) _digit(val[i], '$prefix$i'),
        ],
      );

  Widget _digit(String d, String keyPrefix) => AnimatedSwitcher(
        duration: const Duration(milliseconds: 220),
        transitionBuilder: (child, anim) => ScaleTransition(
          scale: anim,
          child: FadeTransition(opacity: anim, child: child),
        ),
        child: Container(
          key: ValueKey('$keyPrefix:$d'),
          width: 30,
          height: 44,
          margin: const EdgeInsets.symmetric(horizontal: 1.5),
          decoration: BoxDecoration(
            color: const Color(0xFF2A1F00),
            borderRadius: BorderRadius.circular(5),
            border: Border.all(
                color: const Color(0xFFFFC107).withOpacity(0.35), width: 1),
          ),
          alignment: Alignment.center,
          child: Text(
            d,
            style: const TextStyle(
              color: Color(0xFFFFC107),
              fontSize: 24,
              fontWeight: FontWeight.bold,
            ),
          ),
        ),
      );

  Widget _sep() => const Padding(
        padding: EdgeInsets.only(left: 3, right: 3, bottom: 4),
        child: Text(
          ':',
          style: TextStyle(
              color: Color(0xFFFFC107),
              fontSize: 28,
              fontWeight: FontWeight.bold),
        ),
      );
}

