                        : null,
                    trailing: Row(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        FutureBuilder<void>(
                          future: _voiceFutures.putIfAbsent(
                            item.id,
                            () => _fetchVoiceUrl(item.id).then((url) {
                              if (mounted) setState(() => _voiceUrls[item.id] = url);
                            }),
                          ),
                          builder: (_, __) {
                            final hasVoice = _voiceUrls.containsKey(item.id) &&
                                _voiceUrls[item.id] != null;
                            if (!hasVoice) return const SizedBox.shrink();
                            final isPlaying = _playing[item.id] == true;
                            return GestureDetector(
                              onTap: () => _togglePlay(item.id),
                              child: Container(
                                width: 32,
                                height: 32,
                                decoration: const BoxDecoration(
                                  color: Color(0xFF00C853),
                                  shape: BoxShape.circle,
                                ),
                                child: Icon(
                                  isPlaying ? Icons.stop : Icons.play_arrow,
                                  color: Colors.white,
                                  size: 18,
                                ),
                              ),
                            );
                          },
                        ),
                        const SizedBox(width: 8),
                        const Icon(Icons.drag_indicator, color: Colors.grey),
                      ],
                    ),
                  ),
                  ),
                );
              },
            ),
          ),
          const Divider(color: Color(0xFF2A2A3E), height: 1),
          // Save button
          Padding(
            padding: EdgeInsets.fromLTRB(
                16, 12, 16, MediaQuery.of(context).viewInsets.bottom + 20),
            child: SizedBox(
              width: double.infinity,
              height: 50,
              child: ElevatedButton(
                onPressed: _saving
                    ? null
                    : () async {
                        setState(() => _saving = true);
                        await widget.onSave(_items);
                      },
                style: ElevatedButton.styleFrom(
                  backgroundColor: Colors.blueAccent,
                  foregroundColor: Colors.white,
                  shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(14)),
                  disabledBackgroundColor:
                      Colors.blueAccent.withOpacity(0.5),
                ),
                child: _saving
                    ? const SizedBox(
                        width: 22,
                        height: 22,
                        child: CircularProgressIndicator(
                          color: Colors.white,
                          strokeWidth: 2.5,
                        ),
                      )
                    : const Text(
                        'Save Ranking',
                        style: TextStyle(
                            fontSize: 16, fontWeight: FontWeight.bold),
                      ),
              ),
            ),
          ),
        ],
      ),
    );
  }
